"use client";

import { useState } from "react";
import { useMatchStore } from "../store/useMatchStore";
import { Undo2, Settings, CircleDot, ArrowRightLeft, Trophy, RotateCcw } from "lucide-react";

const TAP_LOCK_MS = 250;

export default function HomePage() {
  const {
    team1,
    team2,
    server,
    isTiebreak,
    useGoldenPoint,
    matchFormat,
    matchWinner,
    matchWinnerDismissed,
    scorePoint,
    undo,
    toggleGoldenPoint,
    toggleServer,
    setMatchFormat,
    resetMatch,
  } = useMatchStore();

  const [tapLocked, setTapLocked] = useState(false);
  const [settingsOpen, setSettingsOpen] = useState(false);

  const handleScore = (team: "team1" | "team2") => {
    if (tapLocked) return;
    setTapLocked(true);
    scorePoint(team);
    window.setTimeout(() => setTapLocked(false), TAP_LOCK_MS);
  };

  const formatPoints = (points: string | number) => {
    if (typeof points === "number") return points.toString();
    return points;
  };

  return (
    <main className="h-screen w-full flex flex-col bg-slate-950 text-slate-50 select-none overflow-hidden p-3 md:p-4 lg:p-6 gap-2 md:gap-4">
      
      {/* --- VICTORY OVERLAY --- */}
      {matchWinner && !matchWinnerDismissed && (
        <div 
          className="absolute inset-0 z-50 flex items-center justify-center bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-500"
          onClick={() => scorePoint("team1")} 
        >
          <div 
            className="relative flex flex-col items-center justify-center bg-slate-900 border-4 border-amber-400 p-8 md:p-12 rounded-[3rem] shadow-[0_0_100px_rgba(251,191,36,0.3)] max-w-[90%] text-center"
            onClick={(e) => e.stopPropagation()}
          >
            <Trophy className="h-20 w-20 md:h-32 md:w-32 text-amber-400 mb-6 animate-pulse" />
            <h2 className="text-5xl md:text-7xl font-black text-white uppercase mb-2">
              {matchWinner === 'team1' ? 'Team 1' : 'Team 2'}
            </h2>
            <h3 className="text-2xl md:text-4xl font-bold text-amber-400 uppercase tracking-widest mb-10">
              Wins the Match!
            </h3>
            <button
              type="button"
              onClick={resetMatch}
              className="inline-flex items-center gap-3 bg-amber-500 text-slate-950 px-8 py-4 md:px-10 md:py-5 rounded-full text-xl md:text-3xl font-black uppercase tracking-wider active:scale-95 transition-transform"
            >
              <RotateCcw className="h-6 w-6 md:h-8 md:w-8" />
              Reset Match
            </button>
          </div>
        </div>
      )}

      {/* Settings Panel */}
      {settingsOpen && (
        <section className="absolute top-20 left-4 right-4 z-40 md:static md:px-2">
          <div className="flex flex-col gap-4 rounded-3xl bg-slate-900/98 px-6 py-5 border border-slate-700 shadow-2xl backdrop-blur-xl">
            <div className="flex items-center justify-between">
              <p className="text-sm md:text-lg font-bold uppercase text-slate-400">Match Length</p>
              <div className="flex bg-slate-800 p-1 rounded-full border border-slate-700">
                {[3, 5].map((num) => (
                  <button
                    key={num}
                    onClick={() => setMatchFormat(num as 3 | 5)}
                    className={`px-4 md:px-6 py-2 rounded-full text-sm md:text-lg font-bold transition-all ${
                      matchFormat === num ? "bg-indigo-500 text-white shadow-lg" : "text-slate-500"
                    }`}
                  >
                    Best of {num}
                  </button>
                ))}
              </div>
            </div>
            <div className="h-px bg-slate-800" />
            <div className="flex items-center justify-between">
              <p className="text-sm md:text-lg font-bold uppercase text-slate-400">Scoring Mode</p>
              <button
                onClick={toggleGoldenPoint}
                className={`px-4 py-2 rounded-full text-sm md:text-lg font-bold border-2 transition-all ${
                  useGoldenPoint ? "border-emerald-500 text-emerald-400 bg-emerald-500/10" : "border-slate-700 text-slate-500"
                }`}
              >
                {useGoldenPoint ? "Golden Point" : "Advantage"}
              </button>
            </div>
          </div>
        </section>
      )}

      {/* Main Scoreboard Area */}
      <section className="flex-1 flex flex-col gap-3 min-h-0">
        {[
          { id: "team1", data: team1, color: "emerald", label: "Team 1" },
          { id: "team2", data: team2, color: "cyan", label: "Team 2" }
        ].map((t) => (
          <button
            key={t.id}
            type="button"
            onClick={() => handleScore(t.id as "team1" | "team2")}
            className={`group flex-1 rounded-[2rem] md:rounded-[3rem] border-4 flex flex-col px-6 md:px-10 py-3 md:py-4 active:scale-[0.99] transition-all relative overflow-hidden ${
              server === t.id
                ? `border-${t.color}-400 bg-${t.color}-500/10 shadow-[0_0_40px_rgba(0,0,0,0.3)]`
                : "border-slate-800/50 bg-slate-900/40"
            }`}
          >
            <div className="flex items-center justify-between w-full h-10 z-20">
              <span className={`text-lg md:text-3xl uppercase font-black tracking-tighter ${server === t.id ? `text-${t.color}-400` : "text-slate-500"}`}>
                {t.label}
              </span>
              {server === t.id && (
                <span className={`flex items-center gap-2 rounded-full bg-${t.color}-500/20 px-4 py-1 text-xs md:text-xl font-black uppercase border border-${t.color}-400/50 text-${t.color}-300`}>
                  <CircleDot className="h-3 w-3 md:h-5 md:w-5" /> Serving
                </span>
              )}
            </div>

            <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-10">
              <span className="text-[10rem] md:text-[15rem] lg:text-[18rem] font-black leading-none tabular-nums tracking-tighter text-white drop-shadow-2xl">
                {formatPoints(t.data.points)}
              </span>
            </div>

            <div className="flex-1 flex items-end justify-between w-full pb-1 md:pb-2 z-20">
              <div className="flex flex-col items-start">
                <span className="text-[10px] md:text-lg text-slate-500 uppercase font-bold">Sets</span>
                <span className="text-6xl md:text-8xl font-black text-slate-200">{t.data.sets}</span>
              </div>
              <div className="flex flex-col items-end">
                <span className="text-[10px] md:text-lg text-slate-500 uppercase font-bold">Games</span>
                <span className="text-6xl md:text-8xl font-black text-slate-200">{t.data.games}</span>
              </div>
            </div>
          </button>
        ))}
      </section>

      {/* Tidy Bottom Control Bar */}
      <footer className="grid grid-cols-3 items-center gap-2 pt-2 border-t border-slate-800/50">
        <div className="flex justify-start">
          <button
            onClick={undo}
            disabled={!!matchWinner && !matchWinnerDismissed}
            className="flex items-center gap-2 bg-slate-900 border border-slate-700 px-4 py-3 md:px-6 md:py-4 rounded-2xl text-sm md:text-xl font-bold active:scale-95 disabled:opacity-30"
          >
            <Undo2 size={20} className="md:w-6 md:h-6" /> Undo
          </button>
        </div>

        <div className="flex flex-col items-center">
          <span className="text-[10px] md:text-xs font-black text-slate-600 uppercase mb-1">Best of {matchFormat}</span>
          <div className={`px-4 py-1.5 md:px-6 md:py-2 rounded-full border text-[10px] md:text-lg font-black uppercase ${
            isTiebreak ? "border-amber-500/50 text-amber-500 bg-amber-500/5" : "border-slate-700 text-slate-400"
          }`}>
            {isTiebreak ? "Tiebreak" : "Regular"}
          </div>
        </div>

        <div className="flex justify-end gap-3 items-center">
          <button onClick={resetMatch} className="hidden md:block text-slate-500 font-bold hover:text-red-400 transition-colors text-sm lg:text-lg">
            Reset
          </button>
          <button
            onClick={() => setSettingsOpen(!settingsOpen)}
            className="p-3 md:p-4 bg-slate-900 border border-slate-700 rounded-2xl active:scale-95"
          >
            <Settings size={20} className="md:w-8 md:h-8" />
          </button>
        </div>
      </footer>
    </main>
  );
}